mapper.sql:
where 1 = 1

    and project_id = #{projectId}


    and api_path like concat('%', trim(#{apiPath}), '%')


    and record_type = #{recordType}

mapper.select:
select id, project_id, api_path, record_type, user_description, conclusion, confidence, evidence_json,
    auto_verify, feedback_verdict, actual_root_cause, expect_keywords, created_at
from analysis_record where id = #{id}
